package v1beta1

import (
	"context"
	"testing"

	"github.com/openshift/multiarch-tuning-operator/api/common/plugins"
)

func TestClusterPodPlacementConfigValidator_ValidateCreate(t *testing.T) {
	v := &ClusterPodPlacementConfigValidator{}
	tests := []struct {
		name    string
		cppc    *ClusterPodPlacementConfig
		wantErr bool
	}{
		{
			name: "nil plugins",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{},
			},
			wantErr: false,
		},
		{
			name: "nil nodeAffinityScoring",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{},
				},
			},
			wantErr: false,
		},
		{
			name: "unique architectures",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "amd64", Weight: 50},
								{Architecture: "arm64", Weight: 50},
							},
						},
					},
				},
			},
			wantErr: false,
		},
		{
			name: "duplicate architectures",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "amd64", Weight: 50},
								{Architecture: "amd64", Weight: 80},
							},
						},
					},
				},
			},
			wantErr: true,
		},
		{
			name: "single architecture",
			cppc: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "arm64", Weight: 100},
							},
						},
					},
				},
			},
			wantErr: false,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, err := v.ValidateCreate(context.Background(), tt.cppc)
			if (err != nil) != tt.wantErr {
				t.Errorf("ValidateCreate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

func TestClusterPodPlacementConfigValidator_ValidateUpdate(t *testing.T) {
	v := &ClusterPodPlacementConfigValidator{}
	tests := []struct {
		name    string
		newObj  *ClusterPodPlacementConfig
		wantErr bool
	}{
		{
			name: "unique architectures on update",
			newObj: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "amd64", Weight: 50},
								{Architecture: "arm64", Weight: 50},
							},
						},
					},
				},
			},
			wantErr: false,
		},
		{
			name: "duplicate architectures on update",
			newObj: &ClusterPodPlacementConfig{
				Spec: ClusterPodPlacementConfigSpec{
					Plugins: &plugins.Plugins{
						NodeAffinityScoring: &plugins.NodeAffinityScoring{
							Platforms: []plugins.NodeAffinityScoringPlatformTerm{
								{Architecture: "s390x", Weight: 50},
								{Architecture: "s390x", Weight: 80},
							},
						},
					},
				},
			},
			wantErr: true,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, err := v.ValidateUpdate(context.Background(), &ClusterPodPlacementConfig{}, tt.newObj)
			if (err != nil) != tt.wantErr {
				t.Errorf("ValidateUpdate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}
